// Define a class called Book
class Book {
  // Properties with type annotations
  title: string;
  author: string;
  pages: number;
  // Constructor runs when we create a new Book instance
  constructor(title: string, author: string, pages: number) {
    this.title = title;
    this.author = author;
    this.pages = pages;
  }
  // Method: returns a summary of the book
  getSummary(): string {
    return `${this.title} by ${this.author} (${this.pages} pages)`;
  }
}
// Create two book objects (instances)
const book1 = new Book('The Hobbit', 'J.R.R. Tolkien', 310);
const book2 = new Book('Dune', 'Frank Herbert', 412);
// Call the method on book1
console.log(book1.getSummary());
console.log(book2.getSummary());
// Expected:
// The Hobbit by J.R.R. Tolkien (310 pages)
// Dune by Frank Herbert (412 pages)
